mapper.select:
SELECT sr.id, sr.user_type, sr.username, sr.nickname, sr.telephone, sr.review_status, sr.review_time, sr.create_time FROM sys_register sr WHERE sr.enabled = '1'
AND sr.user_type = #{req.userType}
AND sr.username LIKE CONCAT(#{req.username},'%')
AND sr.nickname LIKE CONCAT(#{req.nickname},'%')
AND sr.telephone = #{req.telephone}
AND sr.review_status = #{req.reviewStatus}
AND sr.create_time BETWEEN #{req.startTime} AND #{req.endTime}
ORDER BY sr.id DESC
